import { supabase } from "../client";

export const getEvidencias = async () => {


    let { data: Evidencias, error } = await supabase
        .from('Evidencias')
        .select('*');


    return Evidencias;

}


export const getEvidenciaById = async (fantasmaId) => {
    let { data: Evidencia, error } = await supabase
        .from('PruebaFantasma')
        .select(`evidencias (id,prueba)`)
        .eq('fantasmas_id', fantasmaId)

    return Evidencia
}
